 37→class AppearanceSettingsFragment : SettingsFragment() {
 38→    private var mBackgroundImage: SwitchPreferenceCompat? = null
 39→    override val preferenceResource: Int
 40→        get() = R.xml.preferences_appearance
 41→    override val analyticsScreenNameConstant: String
 42→        get() = "prefs.appearance"
 43→
 44→    override fun initSubscreen() {
 45→        // Configure background
 46→        mBackgroundImage = requirePreference<SwitchPreferenceCompat>("deckPickerBackground")
 47→        mBackgroundImage!!.onPreferenceClickListener = Preference.OnPreferenceClickListener {
 48→            if (mBackgroundImage!!.isChecked) {
 49→                try {
 50→                    mBackgroundImageResultLauncher.launch("image/*")
 51→                    mBackgroundImage!!.isChecked = true
 52→                } catch (ex: Exception) {
 53→                    Timber.e("%s", ex.localizedMessage)
 54→                }
 55→            } else {
 56→                mBackgroundImage!!.isChecked = false
 57→                val currentAnkiDroidDirectory = CollectionHelper.getCurrentAnkiDroidDirectory(requireContext())
 58→                val imgFile = File(currentAnkiDroidDirectory, "DeckPickerBackground.png")
 59→                if (imgFile.exists()) {
 60→                    if (imgFile.delete()) {
 61→                        showSnackbar(R.string.background_image_removed)
 62→                    } else {
 63→                        showSnackbar(R.string.error_deleting_image)
 64→                    }
 65→                } else {
 66→                    showSnackbar(R.string.background_image_removed)
 67→                }
 68→            }
 69→            true
 70→        }
 71→
 72→        val appThemePref = requirePreference<ListPreference>(R.string.app_theme_key)
 73→        val dayThemePref = requirePreference<ListPreference>(R.string.day_theme_key)
 74→        val nightThemePref = requirePreference<ListPreference>(R.string.night_theme_key)
 75→        val themeIsFollowSystem = appThemePref.value == Themes.FOLLOW_SYSTEM_MODE
 76→
 77→        // Remove follow system options in android versions which do not have system dark mode
 78→        // When minSdk reaches 29, the only necessary change is to remove this if-block
 79→        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.Q) {
 80→            dayThemePref.isVisible = false
 81→            nightThemePref.isVisible = false
 82→
 83→            // Drop "Follow system" option (the first one)
 84→            appThemePref.entries = resources.getStringArray(R.array.app_theme_labels).drop(1).toTypedArray()
 85→            appThemePref.entryValues = resources.getStringArray(R.array.app_theme_values).drop(1).toTypedArray()
 86→            if (themeIsFollowSystem) {
 87→                appThemePref.value = Theme.fallback.id
 88→            }
 89→        }
 90→        dayThemePref.isEnabled = themeIsFollowSystem
 91→        nightThemePref.isEnabled = themeIsFollowSystem
 92→
 93→        appThemePref.setOnPreferenceChangeListener { newValue ->
 94→            val selectedThemeIsFollowSystem = newValue == Themes.FOLLOW_SYSTEM_MODE
 95→            dayThemePref.isEnabled = selectedThemeIsFollowSystem
 96→            nightThemePref.isEnabled = selectedThemeIsFollowSystem
 97→
 98→            // Only restart if theme has changed
 99→            if (newValue != appThemePref.value) {
100→                val previousThemeId = Themes.currentTheme.id
101→                appThemePref.value = newValue.toString()
102→                updateCurrentTheme(requireContext())
103→
104→                if (previousThemeId != Themes.currentTheme.id) {
105→                    ActivityCompat.recreate(requireActivity())
106→                }
107→            }
108→        }
109→
110→        dayThemePref.setOnPreferenceChangeListener { newValue ->
111→            if (newValue != dayThemePref.value && !systemIsInNightMode(requireContext()) && newValue != Themes.currentTheme.id) {
112→                ActivityCompat.recreate(requireActivity())
113→            }
114→        }
115→
116→        nightThemePref.setOnPreferenceChangeListener { newValue ->
117→            if (newValue != nightThemePref.value && systemIsInNightMode(requireContext()) && newValue != Themes.currentTheme.id) {
118→                ActivityCompat.recreate(requireActivity())
119→            }
120→        }
121→
122→        // Show estimate time
123→        // Represents the collection pref "estTime": i.e.
124→        // whether the buttons should indicate the duration of the interval if we click on them.
125→        requirePreference<SwitchPreferenceCompat>(R.string.show_estimates_preference).apply {
126→            launchCatchingTask { isChecked = withCol { config.get("estTimes") ?: true } }
127→            setOnPreferenceChangeListener { _, newETA ->
128→                val newETABool = newETA as? Boolean ?: return@setOnPreferenceChangeListener false
129→                launchCatchingTask { withCol { config.set("estTimes", newETABool) } }
130→                true
131→            }
132→        }
133→        // Show progress
134→        // Represents the collection pref "dueCounts": i.e.
135→        // whether the remaining number of cards should be shown.
136→        requirePreference<SwitchPreferenceCompat>(R.string.show_progress_preference).apply {
137→            launchCatchingTask { isChecked = withCol { config.get("dueCounts") ?: true } }
138→            setOnPreferenceChangeListener { _, newDueCountsValue ->
139→                val newDueCountsValueBool = newDueCountsValue as? Boolean ?: return@setOnPreferenceChangeListener false
140→                launchCatchingTask { withCol { config.set("dueCounts", newDueCountsValueBool) } }
141→                true
142→            }
143→        }
144→    }
145→
146→    private val mBackgroundImageResultLauncher = registerForActivityResult(ActivityResultContracts.GetContent()) { selectedImage ->
147→        if (selectedImage != null) {
148→            // handling file may result in exception
149→            try {
150→                val filePathColumn = arrayOf(MediaStore.MediaColumns.SIZE)
151→                requireContext().contentResolver.query(selectedImage, filePathColumn, null, null, null).use { cursor ->
152→                    cursor!!.moveToFirst()
153→                    // file size in MB
154→                    val fileLength = cursor.getLong(0) / (1024 * 1024)
155→                    val currentAnkiDroidDirectory = CollectionHelper.getCurrentAnkiDroidDirectory(requireContext())
156→                    val imageName = "DeckPickerBackground.png"
157→                    val destFile = File(currentAnkiDroidDirectory, imageName)
158→                    // Image size less than 10 MB copied to AnkiDroid directory
159→                    if (fileLength < 10) {
160→                        (requireContext().contentResolver.openInputStream(selectedImage) as FileInputStream).channel.use { sourceChannel ->
161→                            FileOutputStream(destFile).channel.use { destChannel ->
162→                                destChannel.transferFrom(sourceChannel, 0, sourceChannel.size())
163→                                showSnackbar(R.string.background_image_applied)
164→                            }
165→                        }
166→                    } else {
167→                        mBackgroundImage!!.isChecked = false
168→                        UIUtils.showThemedToast(requireContext(), getString(R.string.image_max_size_allowed, 10), false)
169→                    }
170→                }
171→            } catch (e: OutOfMemoryError) {
172→                Timber.w(e)
173→                showSnackbar(getString(R.string.error_selecting_image, e.localizedMessage))
174→            } catch (e: Exception) {
175→                Timber.w(e)
176→                showSnackbar(getString(R.string.error_selecting_image, e.localizedMessage))
177→            }
178→        } else {
179→            mBackgroundImage!!.isChecked = false
180→            showSnackbar(R.string.no_image_selected)
181→        }
182→    }
183→}
